insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2017-12-19','(Pedro)Conversación con Asunción Cabrera. +++Se le informa de la conversación mantenida con la hermana de Manuel en el día de ayer. +++ALTERNATIVAS: +++++Hará lo posible para que después de Navidad Manuel pueda acceder a una plaza de Pisos Supervisados: difícil, dado que está el nº 12 en la lista de espera. +++++Si el recurso anterior no es posible, se le propondrá que a partir de Reyes empiece a buscar un piso de ALQUILER en MÉRIDA. Esto permitiría mantener el contacto y supervisión de la situación tanto con el CSS como con la CTAEx. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Reunión mantenida con D. Manuel a las 10:00h hasta las 11:25h). Presentes también Amalia y Pedro. +++SE le pone al corriente de la situación en relación al piso de Badajoz, tras la conversación manetnida ayer con su hermana (sin hacer refencia a los problemas que Mª José refirió en la conversación). +++ALTERNATIVAS que se le plantean: +++++Esta el 12º en pisos supervisados. Él NO QUIERE ir a ningún piso. +++++Alquilar un piso en Mérida, para garantizar mayor proximidad al CSS y a la CTAEx de cara a su seguimiento. Esta segunda opción le parece aceptable, a pesar de que se siente muy defraudado por no poder volver a Badajoz, culpando a la CTAEx y al CSS de los problemas de relación que tiene con su hermana y sin hacer autocrítica sobre las oalabras que el mismo dice haberle dirigido a su hermana en estas últimas semanas. +++Insiste en que no quiere piso supervisado y que quiere empezar ya a buscar piso. Se le indica que, en opinión de la CTAEx, sería mejor que pasase antes por psios supervisados, para que el cambio de situación fuese más progresivo, haciéndole las dificultades que el vivir solo pueden suponerle de cara a mantener un equilibrio en aspectos como la continuidad del trataminto, la asistencia a las consultas, y el paso del tiempo en soledad sin nada en qué ocupar dicho tiempo. +++Durante la entrevista llama a su hermana para "confirmar" lo que le estoy diciendo y, en un momento de dicha llamada su hermana Mª José le dice claramente que no quiere que vuelva al piso. Él le dice que es la Comisión y el CSS los que le hemos dicho que ella le tiene que dar la llave del piso (cosa que no es cierta), así como que nosotros somos los que hemos embarullado las cosas para que su hermana esté tan "dolida" con él como a él le parece que está. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Mª José, hermana de Manuel, para dejar claro en qué términos se ha desrrollado la reunión y desmentir los aspectos que su hermano le ha transmitido en la llamada realizada. +++Tras salir de la reunión, comenta su hermana que la ha vuelto a llamar por teléfono. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Asun para ponerla al corriente de la entrevista con manuel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='CANO'and apellido2='HURTADO'),'2017-12-19','CIERRE POR FALLECIMIENTO ANTERIOR A LA ACEPTACIÓN DEL CARGO Tras solicitar, para la realización del inventario, información sobre pensiones a INSS y PNC, se reciben sendos oficios de ambos indicando el fallecimiento de Dña. María. Acaecido, según parece, el 24/05/2017.**********************Mediante fax, se comunica al Jzdo. nº. 2, de Almendralejo, la incidencia. Se incluye copia de los oficios. A 19/12/2017, no se ha recibido comunicación alguna por parte del juzgado.','2');
