insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2017-12-19','-AMALIA: ME INFORMA MARIBEL ( DTRA. APROSUB . 9 ) QUE HA TENIDO INTENTO AUTOLITICO . SE HA TOMADO UN BOTE DE COLONIA DE 1 LITRO Y VA A SER TRASLADADA AL HOSPITAL DE MERIDA. - TRABAJO INVESTIGACION: MIRAR EN SU EXPEDIENTE PARA VER SI TENEMOS DATOS DE LOS PADRES , NOMBRE , APELLIDOS , DNI . SABEMOS QUE AMBOS HAN FALLECIDO PARA SOLICITARLE P. ORFANDAD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='RANGEL'and apellido2='MONROY'),'2017-12-19','-AMALIA: PERCIBIA PNC INVALIDEZ DE 368.90€. DESDE APROSBA 9 SE TRAMITA P. ORFANDAD SIMPLE POR 194€. TB SE HA TRAMITADO PFHC AÚN SIN RESOLVER. DE PNC NOS COMUNICAN QUE SE LE REDUCE LA PNC A 338€ HACIENDOLO COMPATIBLE CON LA P. ORFANDAD . SERIA MÁS VENTAJOSO MANTENER LA PNC QUE LA PFHC . SE LE COMUNICA A LA DTRA. AP 9 .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-12-20','(Pedro) Llamada de María Moruno, de Plena Inclusión Extremadura (924-315911). +++A raíz del contacto que mantuve con Plena Inclusión en la búsqueda de recurso para Beatriz antes de dar a luz, llama la compañera interesándose por la situación. Se le inofrma que nuestra tutelada ya se encuentra residiendo en un centro y que, por el momento, no se requiere ninguna otra intervención. +++No obstante, le comento a María que nos quedamos con su contacto por si en un futuro considerásemos necesraio volver a contactar con Plena Inclusdión de Extremadura.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2017-12-20','El Juzgado de Primera Instancia e Instrucción nº 6, de Cáceres, condena a J.M. a la pena de 5 días de localización permanente y la prohibición de comunicación por cualquier medio con María Nerea Romero Carretero durante un plazo de 6 meses menos un día, imponiéndole el pago de las costas. Comunicamos al Juzgado que reside en el CRR de Mérida, a efectos del cumplimiento de la misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2017-12-20','Hablo con Alfonso Serrano (918459013), abogado que se puso en contacto con nosotros para el tema de la herencia. Me dice que va a contactar con Daniel, hermano de Antonia, para que le facilite información y procedamos a regularizar la herencia por la muerte de la otra hermana. Ésta no hizo testamento y cree que dejó dinero en cuenta bancaria (8-9000 euros, cree). Me llama.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='FERNANDEZ'and apellido2='SERRANO'),'2017-12-20','CAMBIO DOMICILIO DEPENDENCIA Llega "Recibí" de clara a nuestra solicitud de cambio de domicilio. Signa en el mismo que se ha producido el cambio para que nos lleguen a nosotros las notificaciones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2017-12-19','FUGA El 19/12/2017. "Se informa que el paciente ingresado en este Centro Sociosanitario (es el de Mérida) D. Miguel Ángel Gamero Gómez se ha fugado de dicho centro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2017-12-21','El abogado de Álvaro, Juan María Expósito Rubio, ha contestado a la demanda ante el Juzgado de Primera instancia nº 7, de Cáceres, que en su día presentó Nilva Iris, en relación con la impugnación del testamento de los abuelos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORA'and edp.apellido1='LEAL'and apellido2='ROMAN'),'2017-12-21','El abogado de Isidora, César Soler, nos ha enviado el Auto 176/2017, del Juzgado de Primera Instancia e Instrucción nº 6, de Cáceres, en el que autorizan para que aceptemos la herencia de su marido, Juan Leo Mogollón. No es firme aún. Nos envía la factura y el testimonio del Auto una vez sea firme.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='TREJO'and apellido2='COLLADO'),'2017-12-20','(Pedro)Llamada a última hora de Francisco del Arco, Jefe de Sala del 112 (924-310204). +++Les ha llegado el Auto del Juzgado de 1ª instancia nº 6 de Cáceres autorizando el ingreso NO voluntario de Dª María Luisa en la Residencia "Felipe TRigo". +++No nos ha llegado a nosotros, que solamente tenemos la Defensa Judicial. Indica que la activación del 112 depende del médico de cabecera en el caso de que el traslado no sea voluntario. Si lo fuese, sería el respeondable de esta señora quien tuviese que facilitarlo. +++Solicita el teléfono de Cristina Lancho. Le doy el de su Secretaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='TREJO'and apellido2='COLLADO'),'2017-12-21','(Pedro)Conversaciones con : +++FRANCISCO. Jefe de Sala(112). *******Finalmente no llamó a la Territorial de Cáceres.Va a llamar al Juzgado para tratar de aclarar la situación. *******Si el internamiento es voluntario, ha de ser el responsable legal quien lo lleve a cabo; si es involuntario, laactivación del protocolo le corresponde al Médico de Cabecera. +++ABOGACÍA DE LA JUNTA: José Ángel Rodríguez, letrado que lleva la D. Judicial (924-003938). *******SE le pide infdormación sobre la capacidad de la CTAEX para intervenir en este intermanineto, al ser solamnete D. Judiciales. +++JUZGADO nº 6 de Cáceres: *******La Jueza no está, pero me informan de que han enviado el Auto de internamiento al Ayuntamiento de Almoharín y al C. Salud de la localidad. +++SSB de ALMOHARÍN: José Antonio, T.Social del SSB. *******SE le pide que se queden las llaves de Dª Mª Luisa en el Ayuntamiento. +++MÉDICO DE FAMILIA: Dr. Alfonso Acero (927-386474). *******Ya ha inciado la activación del 112 y a lo largo de la mañana se hará el traslado de Dª Mª Luisa. +++FRANCISCO, Jefe de Sala: *******Confirma activación por parte del Médico. +++RESIDENCIA "FELIPE TRIGO". Nieves, T. Soc: *******SE le comunica que se va a realizar a lo largo de la mañana este traslado. +++ABOGACÍA DE LA JUNTA: José Ángel Rodríguez, letrado que lleva la D. Judicial (924-003938). *******SE le informa de que el traslado se va a llevar a cabo a lo largo de esta mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='NEVADO'and apellido2='NAVARRO'),'2017-12-22','SALIDA Entre el 22/12/2017 y el 26/12/2017. "...quería comentaros que dado que en la última visita que hizo José a su domicilio se escondió a su regreso, consideramos arriesgado que siga yendo solo en el autobús a Badajoz (por si se baja del autobús en alguna para y se pierde), por lo que solicitaremos que en esta ocasión José Antonio Nevado pueda ir en taxi, dado que no puede venir a recogerle su familia. Iría el día 22/12 y regresaría el día 26/12."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2017-12-22','PENSIÓN Se remite solicitud de PNC por invalidez.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2017-12-22','Buenos días. Soy Anabel, del equipo de valoración de depedencia de Cáceres. Tenemos que hacer la revision de SATURNINO MIGUEL SALGADO JIMENEZ y solamente tenemos como telefono de contacto el vuestro pero no somos capaces de hablar con vosotros. Os dejo nuestro telefono: 689575711/ 927006788 para que nos pongamos en contacto y podamos concertar la cita para la valoración. Un saludo. Se responde por teléfono a este correo: +++Se informa de que Saturnino se encuentra ingresado en la UME del CSS de Plasencia.Toma nota la compañera que coge la llamada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2017-12-22','(Pedro) Conversación con Cristina (Directora de Plena Inclusión Llerena). 924-871037. +++Ha recibido ayer, 21 de diciembre, la visita de su padre, de su tío paterno y de Dª Emilia,la mujer de éste (626984221).Ambos viven en Toledo.Se fueron a comer y regresaron a las 17:00h. +++Pidieron a la familia que no le generaran falsas expectativas con aquello que le pudieran decir.Beatriz se puso muy contenta +++El padre de Beatriz se quejaba de que estaba tan lejos que él no la podía ir a visitar todo lo que quisiera y que la echaba mucho de menos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2017-12-22','(Pedro)Visita de Gisela (T. Soc.) y Beatriz (Psicol.) del CRR de Mérida: +++Consuelo se escapó ayer del Centro y hoy han recibido la llamada del SAMUR Social informando de que estaba en Madrid y que no quería volver a Mérida. +++CONTACTO CON SAMUR SOCIAL. Yois, agente del Samur (914-802020) comunica que esta mañana la han tenido que trasladar a URGENCIAS de la FUNDACIÓN JIMÉNEZ DÍAZ (915-504800) por sufrir una crisis y en el momento de estar conversación seguía en dicho Servicio. +++CONTACTO CON la FUNDACIÓN JIMÉNEZ DÍAZ +++++SARA T. Soc. (915-505332). Yois me da el contacto pero no consigo hablar con ella. +++CONTACTO con URGENCIAS de la FUNDACIÓN JIMÉNEZ DÍAZ +++++Hablo con un Médico (no se identifica) que informa que le van a dar el alta en Urgencias y cree que la van a ingresar en Psiquiatría, aunque no lo tiene confirmado.Le pido el nombre del Psiquiátra que la ha atendido: la Dra. MARÍA CONSTANZA. +++CONTACTO CON UNIDAD de PSIQUIATRÍA: ++++++Me pasan con la Dra. pero no consigo hablar con ella. +++CONTACTO con ROBERTO, T. Soc. de la Fundación (915-447206). ++++++Me dice que va a intentar averiguar como está la situación y me dice que la T. Social de Psiquiatría es Laura, pero que no me preocupe que él va a hacer las gestiones pertinentes sobre el caso y me vuelve a llamar. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++INTERVENCIÓN++++++++++++++++++++++++++++++++++++++++ RETORNO A MÉRIDA: ++++++++Si finalmente queda INGRESADA, se haría en su momento un traslado interhospitalario para traerla al Hospital de Mérida. ++++++++Si finalmente se le da el ALTA, la única seguridad de su vuelta al CRR sería mediante la CONTRATACIÓN de un servicio PRIVADO de AMBULANCIA: el riesgo de huída en caso de transporte público hace que se descarte dicha posibilidad. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++CONSUELO QUEDA INGRESADA EN LA PLANTA DE PSIQUIATRÍA (915-504800/ ext. 4987 y 3394) hasta que el martes 26 de diciembre se realice la valoración de su estado. +++Dra. que la atendió en Urgencias: Dra. Mª Constanza Vera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='BARQUERO'and apellido2='MARTIN'),'2017-12-22','TRASLADO A HOSPITAL El 22/12/2017. Será trasladado al Hospital de Mérida. Informa el CSS de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2017-12-22','Enviamos autorización a Pablo Guillén Caro, habilitado de clases pasivas, para que presente la liquidación de los impuestos de sucesiones y plusvalías, por la herencia de la madre de Ceferino.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2017-12-26','Envío documentación al abogado, Ignacio Sánchez de León Silvestre, de Valencia, para que inicie la reclamación a Poblanc, en relación con el alquler del local de Mora de Rubielos, 14-4, de Valencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NICANOR'and edp.apellido1='IÑAÑEZ'and apellido2='CORTES'),'2017-12-26','Enviamos a la abogada, Mirian Gómez Navarro, documentación relacionada con la herencia de Casimiro, hermano de Nicanor.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2017-12-26','En relación con la Ejecutoria 49/2015, en el que condenan a Julian Vivas Paz, por un delito de abuso sexual, al pago de una indemnización a favor de Concepción, al no poder pagarla, ofrece la opción que, tanto como Concepción como Emilia Montes García, se queden con su casa. Al estar valorada esta en cuantía superior a la responsabilidad civil y no acudir a la subasta pública, queda desierta la misma y se archiva. Julián sigue en prisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GABRIEL'and edp.apellido1='SOBRINO'and apellido2='TARDIO'),'2017-12-26','Fiscalía presenta demanda de reintegración de la capacidad de Juan Gabriel y lo envía al Juzgado de 1º. Instanci nº 5, de cáceres, para que dicte sentencia declarando la reintegración de la capacidad respecto al ejercicio del derecho al voto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='ARNEDO'and apellido2='LOPEZ'),'2017-12-26','Hemos recibido autorización para vender las fincas de Los Guájeres, en Granada. Pero lo autorizan por el valor mínimo de tasación (34.610 euros), cuando la oferta recibida es de 25.000 euros. El abogado va a enviar escrito al Juzgado indicando esta circunstancia, para que nos permitan poder venderlas por el importe de la oferta recibida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2017-08-03','Envío un correo a José Tello, en relación con la venta de la finca. Le comento que la misma pertenece proindiviso a las dos hermanas, una de ellas fallecida. Habría que hacer primero la herencia y después venderla. Por ese motivo, debido a los gastos que supondrían la gestión de los trámites para la herencia y posterior compraventa, la avanzada edad de Sofía, le indico que consideramos más beneficioso para ella orientar sus gastos hacia sus necesidades más básicas. Pedimos presupuestos a varias empresas de limpieza. Se plantea aquí la posibilidad de un arrendamiento con aprovechamiento, a cambio de mantenerla limpia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2017-12-27','En relación con la factura abonada el 15/12/2016, a la notaría de María del Pilar Carrascal Peñuela, de Villanueva de la Serena, con motivo de la escritura de compraventa del 50% de la vivienda de protección oficial, sita en C/. Infanta Cristina, nº 35, de Navalvillar de Pela, solicito a la notaría nos envíen copia de la escritura, con nº de protocolo 1.633. En Registro de la Propiedad de Puebla de Alcócer, aparece como titular al 100% de esa vivienda. En el catastro, aparece como titular al 100% de otra vivienda, en la misma calle pero en el número 40. Al parecer, según el Ayuntamiento, es la misma vivienda. Nos envían certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2017-12-26','Hoy por la tarde ha sido el regreso de Consuelo al CRR de Mérida, desde la Fundación Jiménez Díaz de Madrid, en ambulancia privada al venir con el alta médica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2017-12-27','(Pedro)Conversación con Javier Niso, del CRR de Mérida (924-304538). +++Pregunto por Consuelo: llegó ayer por la tarde, tranquila y ha pasado el día también es ese estado. +++DEcía que se marchó porque en el Centro se encontraba bien y quería ver a Bisbal. +++Hoy VAN A IR A VERLA SUS PADRES, quienes han manifestado su deseo de que pase unos días con ellos. Javier, el Director del CRR, considera que dadas las circunstancias, no es aconsejable esta salida en estos momentos. Se manifiesta el apoyo por parte de esta CTAEX a dicha consideración, dada además la relación "tensa" que mantiene con ellos. SE puede valorar dicha salida para más adelante.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2017-12-27','(Pedro)Llamada de D. Feliciano Villares Poderoso (696-549451). +++REmitió ayer un escrito interesándose por la adquisición de dos fincas. +++Interesado en el mantenimiento de las fincas, SIN COSTE, A CAMBIO DE SU APROVECHAMIENTO. +++Si se diese la posibilidad de compra, también estrían interesados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2017-12-27','(Pedro)Llamada de Julia, madre de José Mª. +++Tiene cita en CADEx el 19 de enero (verificar). +++En Vera le han comentado que tienen que ir a llevarlo y luego que se quede con ellos el fin de semana. +++Soliictar información a Cintia, T. Soc. de Vera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='DELGADO'and apellido2='ROMERO'),'2017-12-27','2 correos-e de Julia, T. Soc. de Rosalba. +++PRIMERO: Buenos días, según conversación mantenida, adjunto envío Documento de Aceptación PIA de DÑA. ROSA DELGADO ROMERO y Documento de Guardador de hecho para la firma por la CTA. Mañana a primera hora pasaré a recoger la documentacion. Aprovecho para informarles que desde Rosalba se ha gesitonado el acompañamiento en el Hospital de Mérida de Dña. ROSA DELGADO durante su estancia. Estará acompañada de 12:00-14:00 h para la comida y de 19:00 h -21:00 h para la cena,. +++SEGUNDO:Buenos días de nuevo, en relación a la Incapacitada DÑA ROSA DELGADO ROMERO, les informo que acabo de mantener conversación telefónica con DÑA. EULALIA MEJÍAS DELGADO (prima de Rosa Delgado), me informa que viene de camino de Madrid que esta cerca de Trujillo y que va al hospital que ella se va a encargar de acompañar a Rosa en el hospital , que se lo diga a la CTA y que avise a la cuidadora para que no vaya mas. Le he comunicado que hablaría primero con la CTA y después la llamaba de nuevo. Según la conversación mantenida con Pedro Gracia, hasta nueva orden la cuidadora EVA HURTADO LOZANO seguirá acompañándola en el hospital de 12.00 h -14:00 h y de 19:00h-21:00h. En este momento Informaré a DÑA EULALIA MEJÍAS que contacte con la CTA para quedar constancia de las actuaciones que llevarán a cabo. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Visita de Dª Eulalia a la CTAEx (junto a su marido). +++QUIERE QUEDARSE A CUIDAR A SU PRIMA MIENTRAS PERMANEZCA INGRESADA. +++Durante el día de hoy se quedará EVA, una cuidadora con la que la CTAEx había ya contactado con anterioridad. Se le explica a su prima está circunstancia y, a partir de mañana, será ella la que se quede con Dª Rosa al menos, durante el mismo horario que lo hacía Eva. +++Informo de ello a Beatriz, Directora de Rosalba. +++Estaremos pendientes del Hospital','2');
